// ── 文件生成器 ──

function writeChapterFile(dir, chapter) {
  const content = `# 第${chapter.number}章 · ${chapter.title}

${'这是一段测试正文内容。'.repeat(Math.max(1, Math.floor((chapter.wordCount || 1000) / 15)))}

本章状态: ${chapter.status === 'done' ? '✅ 已完成' : chapter.status === 'in_progress' ? '⟳ 进行中' : '⏹ 未开始'}
`;
  fs.writeFileSync(path.join(dir, chapter.file), content);
}

function writeOutlineFile(dir, skillName) {
  fs.writeFileSync(path.join(dir, 'outline.md'), `# 故事大纲

## ${skillName} — E2E 测试大纲

### 核心梗概
这是一份 E2E 测试用的大纲文件。用于验证应用在大纲阶段的行为。

### 章节目录
- 第一章: 开端
- 第二章: 发展
- 第三章: 高潮
- 第四章: 结局
`);
}

function writeCharacterFile(dir) {
  fs.writeFileSync(path.join(dir, 'character.md'), `# 人物小传

## 主角
- 姓名: 测试角色 A
- 年龄: 28
- 职业: 小说家

## 配角
- 姓名: 测试角色 B
- 年龄: 32
- 职业: 编辑
`);
}

function writeChapterIndexFile(dir, chapters) {
  const chapterList = chapters
    .map((ch, i) => `${i + 1}. 第${ch.number}章 · ${ch.title} [${ch.status === 'done' ? '✅' : '⏹'}]`)
    .join('\n');

  fs.writeFileSync(path.join(dir, 'chapter-index.md'), `# 章节目录

> E2E 测试用章节目录

${chapterList}
`);
}

// ── 主函数 ──

function setupFixtures(baseDir, customFixtures) {
  const fixtures = customFixtures || DEFAULT_FIXTURES;
  const projectRoot = path.join(baseDir, '..'); // do-zhou/
  const dataDir = path.join(projectRoot, '写作项目-E2E-test-fixtures');

  console.log(`🧪 创建测试数据: ${dataDir}`);

  // 清理旧数据
  if (fs.existsSync(dataDir)) {
    fs.rmSync(dataDir, { recursive: true, force: true });
  }
  fs.mkdirSync(dataDir, { recursive: true });

  // 创建 Skills
  for (const skill of fixtures.skills) {
    const skillDir = path.join(dataDir, skill.name);
    fs.mkdirSync(skillDir, { recursive: true });

    // Skill 元数据
    const skillMeta = {
      name: skill.displayName,
      version: skill.version,
      description: skill.description,
      stages: skill.stages,
    };
    fs.writeFileSync(path.join(skillDir, 'skill.json'), JSON.stringify(skillMeta, null, 2));

    // 创建 CLAUDE.md (Skill 的核心文件)
    fs.writeFileSync(path.join(skillDir, 'CLAUDE.md'), `# ${skill.displayName}

## 角色
你是一位专业的${skill.description}

## 写作方法论
- 大纲先行，人物驱动
- 每章 3000-5000 字
- 对话与叙述比例 4:6
`);

    // 创建大纲模板
    writeOutlineFile(skillDir, skill.displayName);

    // 创建人物模板
    writeCharacterFile(skillDir);

    // 创建 templates 目录
    const templatesDir = path.join(skillDir, 'templates');
    fs.mkdirSync(templatesDir, { recursive: true });
    fs.writeFileSync(path.join(templatesDir, 'chapter-template.md'), `# 第{N}章 · {标题}

> {一句话摘要}

## 正文

{内容}

---
字数: {wordCount}
`);
  }

  // 创建项目目录
  for (const project of fixtures.projects) {
    const projectDir = path.join(dataDir, project.skillName, 'projects', project.name);
    fs.mkdirSync(projectDir, { recursive: true });

    // 项目元数据
    fs.writeFileSync(path.join(projectDir, 'project.json'), JSON.stringify({
      name: project.displayName,
      skillName: project.skillName,
      createdAt: new Date().toISOString(),
    }, null, 2));

    // 创建章节文件
    const chaptersDir = path.join(projectDir, 'chapters');
    fs.mkdirSync(chaptersDir, { recursive: true });

    for (const chapter of project.chapters) {
      if (chapter.status === 'pending' && chapter.wordCount === 0) {
        // 空章节: 创建空文件
        fs.writeFileSync(path.join(chaptersDir, chapter.file), '');
      } else {
        writeChapterFile(chaptersDir, chapter);
      }
    }

    // 创建章节目录
    if (project.chapters.length > 0) {
      writeChapterIndexFile(projectDir, project.chapters);
    }

    // 创建 outline.md 和 character.md
    writeOutlineFile(projectDir, project.skillName);
    writeCharacterFile(projectDir);
  }

  // 创建回收站数据
  if (fixtures.recycleBin && fixtures.recycleBin.length > 0) {
    const trashDir = path.join(dataDir, '.trash');
    fs.mkdirSync(trashDir, { recursive: true });
    for (const item of fixtures.recycleBin) {
      fs.writeFileSync(path.join(trashDir, `${item.name}.json`), JSON.stringify(item, null, 2));
    }
  }

  console.log(`✅ 测试数据就绪: ${fixtures.skills.length} Skills, ${fixtures.projects.length} 项目, ${fixtures.recycleBin?.length || 0} 回收站项`);
  return dataDir;
}

function cleanupFixtures(baseDir) {
  const projectRoot = path.join(baseDir, '..');
  const dataDir = path.join(projectRoot, '写作项目-E2E-test-fixtures');
  if (fs.existsSync(dataDir)) {
    fs.rmSync(dataDir, { recursive: true, force: true });
    console.log('🧹 测试数据已清理');
  }
}

module.exports = { setupFixtures, cleanupFixtures, DEFAULT_FIXTURES };

/**
 * 用户故事 E2E — 按 Spec→E2E 深度标准自动生成
 * 每条测试 = 操作 → 等待结果 → 验证最终状态
 */
import { test, expect, _electron as electron } from '@playwright/test'
import path from 'path'

const EP = path.join(__dirname, '..', 'node_modules', 'electron', 'dist', 'electron.exe')
const MAIN = path.join(__dirname, '..', 'out', 'main', 'index.js')

async function waitForBody(page, minLen, timeout) {
  if (!minLen) minLen = 30; if (!timeout) timeout = 20000
  var start = Date.now()
  while (Date.now() - start < timeout) {
    var txt = await page.locator('body').innerText().catch(function() { return '' })
    if (txt.length >= minLen) return txt
    await page.waitForTimeout(2000)
  }
  return await page.locator('body').innerText().catch(function() { return '' })
}

test.describe('用户故事验证', function() {
  var app, page

  test.beforeAll(async function() {
    app = await electron.launch({ executablePath: EP, args: [MAIN] })
    page = await app.firstWindow()
    await page.waitForLoadState('load').catch(function() {})
    var txt = await waitForBody(page, 50, 25000)
    expect(txt.length).toBeGreaterThan(0)
  }, 35000)

  test.afterAll(async function() {
    try { await app.close(); await app.process().kill() } catch (e) {}
  })

  // ═══ 故事1: 导入Skill → 列表出现 → 显示正确元数据 ═══
  test('故事1: 工作台→Skill主页可导航', async function() {
    var homeBtn = page.locator('button[aria-label="主页"]')
    if (await homeBtn.isVisible().catch(function() { return false })) {
      await homeBtn.click()
    }
    var txt = await waitForBody(page, 50, 15000)
    // Skill主页应有"导入"或"技能包"
    var hasSkillPage = txt.indexOf('导入') !== -1 || txt.indexOf('技能包') !== -1 || txt.indexOf('Skill') !== -1
    expect(hasSkillPage).toBe(true)
  })

  // ═══ 故事2: Skill主页→新建项目→工作台文件树有文件 ═══
  test('故事2: Skill主页含回收站和新建按钮', async function() {
    var txt = await page.locator('body').innerText().catch(function() { return '' })
    expect(txt.indexOf('回收站') !== -1).toBe(true)
    expect(txt.indexOf('新建') !== -1).toBe(true)
  })

  // ═══ 故事3: 返回工作台→阶段卡片存在 ═══
  test('故事3: 返回工作台→阶段卡片可见', async function() {
    // 导航回工作台 (点Home或章节目录快捷键)
    await page.keyboard.press('Control+Shift+C')
    await page.waitForTimeout(1500)
    var txt = await page.locator('body').innerText().catch(function() { return '' })
    // 工作台应有"故事大纲"或"创作流程"
    var hasWorkspace = txt.indexOf('故事大纲') !== -1 || txt.indexOf('创作流程') !== -1 || txt.indexOf('章节') !== -1
    expect(hasWorkspace).toBe(true)
  })

  // ═══ 故事4: 无崩溃验证 ═══
  test('故事4: 所有导航无崩溃', async function() {
    var errors = []
    page.on('console', function(msg) { if (msg.type() === 'error') errors.push(msg.text()) })
    // 点Home
    var homeBtn = page.locator('button[aria-label="主页"]')
    if (await homeBtn.isVisible().catch(function() { return false })) { await homeBtn.click(); await page.waitForTimeout(1000) }
    // 再点几个按钮
    var btns = page.locator('button')
    var count = await btns.count()
    for (var i = 0; i < Math.min(count - 5, 4); i++) {
      await btns.nth(i).click().catch(function() {})
      try { await page.waitForTimeout(200) } catch (e) { break }
    }
    // 只检查ReferenceError/TypeError
    var fatal = errors.filter(function(e) {
      return (e.indexOf('ReferenceError') !== -1 || e.indexOf('TypeError') !== -1 || e.indexOf('is not defined') !== -1) &&
             e.indexOf('Security Warning') === -1 &&
             e.indexOf('React DevTools') === -1
    })
    expect(fatal.length).toBe(0)
  })

  test('故事5: 导航后页面有内容', async function() {
    // 清理可能的残留状态：关闭弹窗、按 Escape、等待渲染
